"use client";

import React, { useState, useCallback, DragEvent } from 'react';
import type { Product } from '../types';
import { Button } from './Button';
import { PhotoIcon, XMarkIcon } from './Icons';
import { getVisualRecommendations } from '../services/geminiService';
import { fileToBase64 } from '../utils';
import { ProductCard } from './ProductCard';

interface VisualSearchPageProps {
  allProducts: Product[];
  onProductSelect: (productId: string) => void;
}

export const VisualSearchPage: React.FC<VisualSearchPageProps> = ({ allProducts, onProductSelect }) => {
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [recommendedProducts, setRecommendedProducts] = useState<Product[]>([]);
  // ... другие состояния ...

  // ... хендлеры файлов ...

  const handleSubmit = useCallback(async () => {
    if (!imageFile) return;
    setIsLoading(true);
    setError(null);
    setRecommendedProducts([]);
    try {
      const base64Image = await fileToBase64(imageFile);
      // --- ИЗМЕНЕНИЕ: Получаем массив индексов ---
      const recommendedIndices = await getVisualRecommendations(base64Image, imageFile.type, allProducts);
      
      if (recommendedIndices.length === 0) {
        setError('Не смогли найти подходящую мебель.');
      } else {
        // --- ИЗМЕНЕНИЕ: Находим товары по индексам ---
        const foundProducts = recommendedIndices
          .map(index => allProducts[index])
          .filter(Boolean); // Фильтруем на случай, если AI вернет неверный индекс
        setRecommendedProducts(foundProducts);
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Произошла неизвестная ошибка.');
    } finally {
      setIsLoading(false);
    }
  }, [imageFile, allProducts]);
  
  // ... JSX остается без изменений ...
};
